import React, { useEffect, useRef } from 'react';
import { ArrowRight } from 'lucide-react';
import gsap from 'gsap';
import AtmosphericVideo from './AtmosphericVideo';
import { videoMap } from '../config/videoMap';

const Hero: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);
  const titleLinesRef = useRef<(HTMLSpanElement | null)[]>([]);
  const textRef = useRef<HTMLParagraphElement>(null);
  const buttonRef = useRef<HTMLButtonElement>(null);
  const topTextRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.fromTo(topTextRef.current,
        { y: 20, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 0.2 }
      );

      gsap.to(titleLinesRef.current, {
        y: 0,
        opacity: 1,
        duration: 1.5,
        stagger: 0.2,
        ease: "power4.out",
        delay: 0.5 
      });

      gsap.fromTo(textRef.current, 
        { y: 30, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 1.2 }
      );

      gsap.fromTo(buttonRef.current,
        { scale: 0.8, opacity: 0 },
        { scale: 1, opacity: 1, duration: 0.8, ease: "back.out(1.7)", delay: 1.4 }
      );
    }, containerRef);

    return () => ctx.revert();
  }, []);

  const addToRefs = (el: HTMLSpanElement | null) => {
    if (el && !titleLinesRef.current.includes(el)) {
      titleLinesRef.current.push(el);
    }
  };

  return (
    <section ref={containerRef} className="relative h-screen w-full overflow-hidden bg-navy-900">
      <AtmosphericVideo videoId={videoMap.hero} opacity={0.6} />

      <div className="absolute inset-0 bg-gradient-to-t from-navy-900 via-transparent to-transparent opacity-80 z-0" />

      <div className="relative z-10 container mx-auto px-6 md:px-12 h-full flex flex-col justify-end pb-24 md:pb-32">
        <div ref={topTextRef} className="mb-6">
            <span className="text-white/70 text-xs md:text-sm font-bold tracking-[0.3em] uppercase block">
                M A D R I D · E S P A Ñ A
            </span>
        </div>

        <div className="max-w-5xl">
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-white leading-[1.05] tracking-tight mb-8">
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">Consultora Inmobiliaria</span>
            </span>
          </h1>
        </div>

        <div className="flex flex-col md:flex-row justify-between items-end border-t border-white/20 pt-8 mt-4">
            <p ref={textRef} className="text-white/80 text-lg md:text-xl font-light max-w-2xl leading-relaxed mb-8 md:mb-0">
              Somos la consultora inmobiliaria liderada por arquitectos; el paso previo indispensable para garantizar el máximo valor en tus decisiones.
            </p>

            <button 
              ref={buttonRef}
              onClick={() => document.getElementById('contacto')?.scrollIntoView({ behavior: 'smooth' })}
              className="hover-trigger bg-white text-navy-900 px-8 py-4 rounded-md flex items-center gap-4 hover:bg-sand-400 transition-all duration-300 group hover:scale-105"
            >
              <span className="text-xs font-bold tracking-[0.2em] uppercase">¿ H A B L A M O S ?</span>
              <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
            </button>
        </div>
      </div>
    </section>
  );
};

export default Hero;

