const BuySection: React.FC = () => {
  const containerRef = useRef<HTMLDivElement>(null);

  const [search, setSearch] = useState('');
  const [maxPrice, setMaxPrice] = useState(25000000);
  const [minBeds, setMinBeds] = useState(0);
  const [minBaths, setMinBaths] = useState(0);

  const filteredProperties = useMemo(() => {
    return properties.filter(prop => {
      const matchesSearch = prop.title.toLowerCase().includes(search.toLowerCase()) || 
                           prop.location.toLowerCase().includes(search.toLowerCase());
      const matchesPrice = prop.priceNum <= maxPrice;
      const matchesBeds = prop.beds >= minBeds;
      const matchesBaths = prop.baths >= minBaths;

      return matchesSearch && matchesPrice && matchesBeds && matchesBaths;
    });
  }, [search, maxPrice, minBeds, minBaths]);

  useEffect(() => {
    const ctx = gsap.context(() => {
      gsap.to('.buy-hero-img', {
        yPercent: 20,
        ease: "none",
        scrollTrigger: {
          trigger: '.buy-hero-wrapper',
          start: "top top",
          end: "bottom top",
          scrub: true
        }
      });

      gsap.from('.property-card', {
        y: 30,
        opacity: 0,
        duration: 0.6,
        stagger: 0.1,
        ease: "power2.out",
        overwrite: true
      });

    }, containerRef);

    return () => ctx.revert();
  }, [filteredProperties]);

  const clearAllFilters = () => {
    setSearch('');
    setMaxPrice(25000000);
    setMinBeds(0);
    setMinBaths(0);
  };

  return (
    <section className="relative min-h-screen pt-32 pb-24" ref={containerRef}>
      <AtmosphericVideo videoId={videoMap.buy} opacity={0.02} />

      {/* Header Image */}
