import React from 'react';

interface AtmosphericVideoProps {
  videoNumber: number;
  opacity?: number;
  className?: string;
}

const AtmosphericVideo: React.FC<AtmosphericVideoProps> = ({ 
  videoNumber, 
  opacity = 0.5, 
  className = "" 
}) => {
  // En Next.js/Vercel, la carpeta 'public' se mapea a la raíz '/'.
  // Por tanto, public/assets/dynamic/1.mp4 se accede como /assets/dynamic/1.mp4
  const videoSrc = `/assets/dynamic/${videoNumber}.mp4`;

  return (
    <div className={`absolute inset-0 w-full h-full overflow-hidden pointer-events-none select-none z-[-10] ${className}`}>
      <video
        autoPlay
        loop
        muted
        playsInline
        className="absolute top-0 left-0 w-full h-full object-cover"
        style={{ opacity }}
      >
        <source src={videoSrc} type="video/mp4" />
      </video>
      {/* Capa de mezcla opcional para homogeneizar el tono con la web */}
      <div className="absolute inset-0 bg-white/5 mix-blend-overlay" />
    </div>
  );
};

