        <div ref={topTextRef} className="mb-6">
            <span className="text-white/70 text-xs md:text-sm font-bold tracking-[0.3em] uppercase block">
                M A D R I D · E S P A Ñ A
            </span>
        </div>

        <div className="max-w-5xl">
          <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-white leading-[1.05] tracking-tight mb-8">
            <span className="reveal-text-container">
               <span ref={addToRefs} className="reveal-text-item">Consultora Inmobiliaria</span>
            </span>
          </h1>
        </div>

        <div className="flex flex-col md:flex-row justify-between items-end border-t border-white/20 pt-8 mt-4">
            <p ref={textRef} className="text-white/80 text-lg md:text-xl font-light max-w-2xl leading-relaxed mb-8 md:mb-0">
