import React, { useRef, useEffect } from 'react';

interface AtmosphericLayerProps {
  videoId: number;
  opacity?: number;
  className?: string;
  overlayColor?: 'white' | 'black' | 'navy';
  mixBlendMode?: 'normal' | 'multiply' | 'overlay' | 'screen';
}

const AtmosphericLayer = React.forwardRef<HTMLDivElement, AtmosphericLayerProps>(({ 
  videoId, 
  opacity = 0.5, 
  className = "", 
  overlayColor = 'white',
  mixBlendMode = 'normal'
}, ref) => {
  const videoRef = useRef<HTMLVideoElement>(null);

  // Asegurar reproducción automática incluso en modo ahorro de energía
  useEffect(() => {
    if (videoRef.current) {
      videoRef.current.defaultMuted = true;
      videoRef.current.muted = true;
      videoRef.current.play().catch(() => {
        // Silently handle autoplay restrictions
      });
    }
  }, []);

  const videoPath = `/assets/dynamic/${videoId}.mp4`;

  // Determinar color del overlay de protección de texto
  const getOverlayClass = () => {
    switch (overlayColor) {
      case 'navy': return 'bg-navy-900';
      case 'black': return 'bg-black';
      default: return 'bg-white';
    }
  };

  return (
    <div ref={ref} className={`absolute inset-0 w-full h-full overflow-hidden pointer-events-none z-0 ${className}`}>

      {/* Capa de Video */}
      <video
        ref={videoRef}
        className="absolute top-1/2 left-1/2 min-w-full min-h-full object-cover -translate-x-1/2 -translate-y-1/2"
        style={{ 
            opacity: opacity,
            mixBlendMode: mixBlendMode as any
        }}
        playsInline
        autoPlay
        muted
        loop
        id={`atmospheric-layer-${videoId}`}
      >
        <source src={videoPath} type="video/mp4" />
      </video>

      {/* Capa de Protección de Contraste (Opcional si se quiere un tintado extra) */}
      {/* Esta capa asegura que si el video falla o tarda, hay un color base */}
      <div className={`absolute inset-0 ${getOverlayClass()} -z-10`} />

    </div>
  );
});

AtmosphericLayer.displayName = "AtmosphericLayer";

export default AtmosphericLayer;

import React, { useEffect, useRef } from 'react';
import { ArrowRight } from 'lucide-react';
import gsap from 'gsap';
