import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import AboutSection from './components/AboutSection';
import BuySection from './components/BuySection';
import SellSection from './components/SellSection';
import RentSection from './components/RentSection';
import Services from './components/Services';
import Founders from './components/Founders';
import Story from './components/Story';
import Contact from './components/Contact';
import Footer from './components/Footer';
import ChatBot from './components/ChatBot';
import Preloader from './components/Preloader';
import CustomCursor from './components/CustomCursor';
import InstaPortfolio from './components/InstaPortfolio';
import InstaEducativo from './components/InstaEducativo';
import InstaLifestyle from './components/InstaLifestyle';

import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import Lenis from 'lenis';

gsap.registerPlugin(ScrollTrigger);

export type ViewState = 'home' | 'buy' | 'sell' | 'rent' | 'insta-portfolio' | 'insta-educativo' | 'insta-lifestyle';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [isLoading, setIsLoading] = useState(true);
  const lenisRef = useRef<Lenis | null>(null);

  useEffect(() => {
    const lenis = new Lenis({
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      smoothWheel: true,
    });

    lenisRef.current = lenis;

    function raf(time: number) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);

    lenis.on('scroll', ScrollTrigger.update);
    gsap.ticker.add((time) => {
      lenis.raf(time * 1000);
    });

    return () => {
      lenis.destroy();
      gsap.ticker.remove(lenis.raf);
    };
  }, []);

  const handleNavigate = (view: ViewState) => {
    setCurrentView(view);
    lenisRef.current?.scrollTo(0, { immediate: true });
  };

  const handleContactClick = () => {
    if (currentView !== 'home') {
      setCurrentView('home');
      setTimeout(() => {
        const contactSection = document.getElementById('contacto');
        if (contactSection) lenisRef.current?.scrollTo(contactSection);
      }, 100);
    } else {
      const contactSection = document.getElementById('contacto');
      if (contactSection) lenisRef.current?.scrollTo(contactSection);
    }
  };

  return (
    <>
      <CustomCursor />
      {isLoading && <Preloader onComplete={() => setIsLoading(false)} />}

      <main className="min-h-screen bg-white flex flex-col overflow-x-hidden">
        <Header onNavigate={handleNavigate} onContactClick={handleContactClick} currentView={currentView} />

        <div className="flex-grow w-full">
          {currentView === 'home' && (
            <div key="home">
              <Hero />
              <AboutSection />
              <Services />
              <Founders />
              <Story />
              <Contact />
            </div>
          )}

          {currentView === 'buy' && <BuySection />}
          {currentView === 'sell' && <SellSection />}
          {currentView === 'rent' && <RentSection />}

          {currentView === 'insta-portfolio' && <InstaPortfolio />}
          {currentView === 'insta-educativo' && <InstaEducativo />}
          {currentView === 'insta-lifestyle' && <InstaLifestyle />}
        </div>

        <Footer onNavigate={handleNavigate} />
        {/* ChatBot oculto en la home, visible en el resto */}
        {currentView !== 'home' && <ChatBot />}
      </main>
    </>
  );
}

export default App;

