interface HeaderProps {
  onNavigate: (view: ViewState) => void;
  onContactClick: () => void;
  currentView: ViewState;
}

const Header: React.FC<HeaderProps> = ({ onNavigate, onContactClick, currentView }) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Removed border-white/10 from the transparent state to eliminate the line
  const navClasses = `fixed w-full z-50 transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] border-b ${
    isScrolled 
      ? 'bg-white/80 backdrop-blur-md border-gray-100 py-4 text-navy-900 shadow-sm' 
      : 'bg-transparent border-transparent py-6 text-white'
  }`;

  const finalTextColor = (currentView !== 'home' && !isScrolled) ? 'text-navy-900' : (isScrolled ? 'text-navy-900' : 'text-white');
  const finalNavClasses = (currentView !== 'home' && !isScrolled) ? 'fixed w-full z-50 py-6 bg-white border-b border-gray-100' : navClasses;

  const handleNavClick = (item: string) => {
    setIsMobileMenuOpen(false);
    const normalizedItem = item.toUpperCase();

    if (normalizedItem === 'COMPRAR') {
      onNavigate('buy');
    } else if (normalizedItem === 'VENDER') {
      onNavigate('sell');
    } else if (normalizedItem === 'ALQUILAR') {
      onNavigate('rent');
    } else if (normalizedItem === 'CONTACTO') {
      onContactClick();
    } else if (normalizedItem === 'NOSOTROS') {
      onNavigate('home');
      setTimeout(() => {
        const el = document.getElementById('nosotros');
        if (el) el.scrollIntoView({ behavior: 'smooth' });
      }, 100);
    } else if (normalizedItem === 'HOME') {
      onNavigate('home');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const menuItems = ['COMPRAR', 'VENDER', 'ALQUILAR', 'NOSOTROS', 'CONTACTO'];

  return (
    <header className={finalNavClasses}>
      <div className="container mx-auto px-6 md:px-12 flex items-center justify-between h-full relative">

        {/* Logo a la izquierda */}
        <div 
          className={`hover-trigger text-3xl md:text-4xl font-italiana tracking-tight cursor-pointer ${finalTextColor}`}
          onClick={() => onNavigate('home')}
        >
          lahuerta
        </div>

        {/* Secciones intermedias (Visible solo en desktop) */}
        <div className="hidden lg:flex items-center space-x-10">
            {menuItems.map((item) => (
                <button 
                    key={item}
                    onClick={() => handleNavClick(item)}
                    className={`hover-trigger text-[10px] font-bold uppercase tracking-[0.3em] hover:opacity-70 transition-opacity ${finalTextColor}`}
                >
                    {item}
                </button>
            ))}
        </div>

        {/* Botón de Menú (Hamburguesa) a la derecha */}
        <button 
          className={`hover-trigger p-2 hover:opacity-70 transition-opacity ${finalTextColor}`}
          onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
        >
           <div className="flex flex-col gap-1.5 items-end">
                <span className="w-8 h-[1px] bg-current"></span>
                <span className="w-6 h-[1px] bg-current"></span>
                <span className="w-8 h-[1px] bg-current"></span>
           </div>
        </button>
      </div>

      {/* Menú Overlay de pantalla completa */}
      <div className={`fixed inset-0 bg-navy-900 z-40 flex flex-col justify-center items-center transition-all duration-700 ease-[cubic-bezier(0.16,1,0.3,1)] ${isMobileMenuOpen ? 'opacity-100 visible' : 'opacity-0 invisible pointer-events-none'}`}>
          <div className="absolute top-8 right-8 md:right-12">
             <button onClick={() => setIsMobileMenuOpen(false)} className="hover-trigger text-white hover:opacity-70">
                <X size={32} strokeWidth={1} />
             </button>
          </div>

          <nav className="flex flex-col items-center space-y-8">
            {['HOME', ...menuItems].map((item, idx) => (
                <button
                  key={item}
                  onClick={() => handleNavClick(item)}
                  className="hover-trigger text-4xl md:text-5xl text-white font-light tracking-tight hover:text-sand-400 transition-colors duration-300 uppercase"
                  style={{ transitionDelay: `${idx * 50}ms` }}
                >
                  {item}
                </button>
            ))}
          </nav>
      </div>
    </header>
  );
};

export default Header;

