import React, { useState, useEffect, useRef } from 'react';
import Header from './components/Header';
import Hero from './components/Hero';
import AboutSection from './components/AboutSection';
import BuySection from './components/BuySection';
import SellSection from './components/SellSection';
import RentSection from './components/RentSection';
import Services from './components/Services';
import Founders from './components/Founders';
import Story from './components/Story';
import Contact from './components/Contact';
import Footer from './components/Footer';
import ChatBot from './components/ChatBot';
import Preloader from './components/Preloader';
import CustomCursor from './components/CustomCursor';
import InstaPortfolio from './components/InstaPortfolio';
import InstaEducativo from './components/InstaEducativo';
import InstaLifestyle from './components/InstaLifestyle';

import gsap from 'gsap';
import { ScrollTrigger } from 'gsap/ScrollTrigger';
import Lenis from 'lenis';

gsap.registerPlugin(ScrollTrigger);

export type ViewState = 'home' | 'buy' | 'sell' | 'rent' | 'insta-portfolio' | 'insta-educativo' | 'insta-lifestyle';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('home');
  const [isLoading, setIsLoading] = useState(true);
  const [showChatBot, setShowChatBot] = useState(false);
  const lenisRef = useRef<Lenis | null>(null);

  useEffect(() => {
    const lenis = new Lenis({
      duration: 1.2,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      smoothWheel: true,
    });

    lenisRef.current = lenis;

    function raf(time: number) {
      lenis.raf(time);
      requestAnimationFrame(raf);
    }

    requestAnimationFrame(raf);

    lenis.on('scroll', ScrollTrigger.update);
    gsap.ticker.add((time) => {
      lenis.raf(time * 1000);
    });

    return () => {
      lenis.destroy();
      gsap.ticker.remove(lenis.raf);
    };
  }, []);

  // Control ChatBot visibility on scroll
  useEffect(() => {
    const handleScroll = () => {
      if (currentView === 'home') {
        // Show after scrolling down 80% of viewport height (past most of hero)
        const threshold = window.innerHeight * 0.8; 
        setShowChatBot(window.scrollY > threshold);
      } else {
        // Always show on other pages
        setShowChatBot(true);
      }
    };

    // Check immediately
    handleScroll();

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [currentView]);

  const handleNavigate = (view: ViewState) => {
    setCurrentView(view);
    lenisRef.current?.scrollTo(0, { immediate: true });
  };

  const handleContactClick = () => {
    if (currentView !== 'home') {
      setCurrentView('home');
      setTimeout(() => {
        const contactSection = document.getElementById('contacto');
        if (contactSection) lenisRef.current?.scrollTo(contactSection);
      }, 100);
    } else {
      const contactSection = document.getElementById('contacto');
      if (contactSection) lenisRef.current?.scrollTo(contactSection);
    }
  };

  return (
    <>
      <CustomCursor />
      {isLoading && <Preloader onComplete={() => setIsLoading(false)} />}

      <main className="min-h-screen bg-white flex flex-col overflow-x-hidden">
        <Header onNavigate={handleNavigate} onContactClick={handleContactClick} currentView={currentView} />

        <div className="flex-grow w-full">
          {currentView === 'home' && (
            <div key="home">
              <Hero />
              <AboutSection />
              <Services />
              <Founders />
              <Story />
              <Contact />
            </div>
          )}

          {currentView === 'buy' && <BuySection />}
          {currentView === 'sell' && <SellSection />}
          {currentView === 'rent' && <RentSection />}

          {currentView === 'insta-portfolio' && <InstaPortfolio />}
          {currentView === 'insta-educativo' && <InstaEducativo />}
          {currentView === 'insta-lifestyle' && <InstaLifestyle />}
        </div>

        <Footer onNavigate={handleNavigate} />

        {/* ChatBot with visibility control */}
        <ChatBot visible={showChatBot} />
      </main>
    </>
  );
}

export default App;

import React, { useEffect, useRef } from 'react';
import { ArrowRight } from 'lucide-react';
import gsap from 'gsap';

const Hero: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const titleLinesRef = useRef<(HTMLSpanElement | null)[]>([]);
  const textRef = useRef<HTMLParagraphElement>(null);
  const topTextRef = useRef<HTMLDivElement>(null);
  const VIDEO_SRC = "/videos/fondocasanovarealestate.mp4"; 

  useEffect(() => {
    // Video Autoplay safety
    if (videoRef.current) {
      videoRef.current.defaultMuted = true;
      videoRef.current.muted = true;
      const playPromise = videoRef.current.play();
      if (playPromise !== undefined) playPromise.catch(() => {});
    }

    // GSAP Animation
    const ctx = gsap.context(() => {
      // 0. Top Text Reveal
      gsap.fromTo(topTextRef.current,
        { y: 20, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 0.2 }
      );

      // 1. Text Reveal (Staggered Lines)
      gsap.to(titleLinesRef.current, {
        y: 0,
        opacity: 1,
        duration: 1.5,
        stagger: 0.2,
        ease: "power4.out",
        delay: 0.5 
      });

      // 2. Body Text Reveal
      gsap.fromTo(textRef.current, 
        { y: 30, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 1.2 }
      );

      // 4. Parallax Effect on Video
      gsap.to(videoRef.current, {
        yPercent: 30,
        ease: "none",
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "bottom top",
          scrub: true
        }
      });
    }, containerRef);

    return () => ctx.revert();
  }, []);

  const addToRefs = (el: HTMLSpanElement | null) => {
    if (el && !titleLinesRef.current.includes(el)) {
      titleLinesRef.current.push(el);
    }
  };

  return (
    <section ref={containerRef} className="relative h-screen w-full overflow-hidden bg-navy-900">
      {/* Background Video with Parallax Wrapper */}
      <div className="absolute inset-0 z-0 h-[120%] -top-[10%]">
        <video 
          ref={videoRef}
          key={VIDEO_SRC}
          className="w-full h-full object-cover opacity-80"
          autoPlay loop muted playsInline preload="auto"
        >
          <source src={VIDEO_SRC} type="video/mp4" />
        </video>
        {/* Overlay Dark Blue/Black gradient */}
        <div className="absolute inset-0 bg-navy-900/20 mix-blend-multiply" />
        <div className="absolute inset-0 bg-gradient-to-t from-navy-900 via-transparent to-transparent opacity-80" />
      </div>

      {/* Content Layout */}
      <div className="relative z-10 container mx-auto px-6 md:px-12 h-full flex flex-col">

        {/* CENTERED: Title & Location (Absoluto al centro de la pantalla) */}
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-full text-center z-20 pointer-events-none">
            <div ref={topTextRef} className="mb-8">
                <span className="text-white/70 text-xs md:text-sm font-bold tracking-[0.3em] uppercase block">
                    M A D R I D · E S P A Ñ A
                </span>
            </div>

            <div className="max-w-6xl mx-auto px-4">
              <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-white leading-[1.05] tracking-tight">
                <span className="reveal-text-container flex justify-center">
                   <span ref={addToRefs} className="reveal-text-item">Consultora Inmobiliaria</span>
                </span>
              </h1>
            </div>
        </div>

        {/* BOTTOM LEFT: Description (Alineado a la izquierda al fondo) */}
