import React, { useEffect, useRef } from 'react';
import { ArrowRight } from 'lucide-react';
import gsap from 'gsap';

const Hero: React.FC = () => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const titleLinesRef = useRef<(HTMLSpanElement | null)[]>([]);
  const textRef = useRef<HTMLParagraphElement>(null);
  const topTextRef = useRef<HTMLDivElement>(null);
  const VIDEO_SRC = "/videos/fondocasanovarealestate.mp4"; 

  useEffect(() => {
    // Video Autoplay safety
    if (videoRef.current) {
      videoRef.current.defaultMuted = true;
      videoRef.current.muted = true;
      const playPromise = videoRef.current.play();
      if (playPromise !== undefined) playPromise.catch(() => {});
    }

    // GSAP Animation
    const ctx = gsap.context(() => {
      // 0. Top Text Reveal
      gsap.fromTo(topTextRef.current,
        { y: 20, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 0.2 }
      );

      // 1. Text Reveal (Staggered Lines)
      gsap.to(titleLinesRef.current, {
        y: 0,
        opacity: 1,
        duration: 1.5,
        stagger: 0.2,
        ease: "power4.out",
        delay: 0.5 
      });

      // 2. Body Text Reveal
      gsap.fromTo(textRef.current, 
        { y: 30, opacity: 0 },
        { y: 0, opacity: 1, duration: 1, ease: "power2.out", delay: 1.2 }
      );

      // 4. Parallax Effect on Video
      gsap.to(videoRef.current, {
        yPercent: 30,
        ease: "none",
        scrollTrigger: {
          trigger: containerRef.current,
          start: "top top",
          end: "bottom top",
          scrub: true
        }
      });
    }, containerRef);

    return () => ctx.revert();
  }, []);

  const addToRefs = (el: HTMLSpanElement | null) => {
    if (el && !titleLinesRef.current.includes(el)) {
      titleLinesRef.current.push(el);
    }
  };

  return (
    <section ref={containerRef} className="relative h-screen w-full overflow-hidden bg-oxblood-900">
      {/* Background Video with Parallax Wrapper */}
      <div className="absolute inset-0 z-0 h-[120%] -top-[10%]">
        <video 
          ref={videoRef}
          key={VIDEO_SRC}
          className="w-full h-full object-cover opacity-80"
          autoPlay loop muted playsInline preload="auto"
        >
          <source src={VIDEO_SRC} type="video/mp4" />
        </video>
        {/* Overlay Oxblood gradient para que el fondo respire el color nuevo */}
        <div className="absolute inset-0 bg-oxblood-900/40 mix-blend-multiply" />
        <div className="absolute inset-0 bg-gradient-to-t from-oxblood-900 via-transparent to-transparent opacity-90" />
      </div>

      {/* Content Layout */}
      <div className="relative z-10 container mx-auto px-6 md:px-12 h-full flex flex-col">

        {/* CENTERED: Title & Location (Absoluto al centro de la pantalla) */}
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-full text-center z-20 pointer-events-none">
            <div ref={topTextRef} className="mb-8">
                <span className="text-white/70 text-xs md:text-sm font-bold tracking-[0.3em] uppercase block">
                    M A D R I D · E S P A Ñ A
                </span>
            </div>

            <div className="max-w-6xl mx-auto px-4">
              <h1 className="text-5xl md:text-7xl lg:text-8xl font-serif text-white leading-[1.05] tracking-tight">
                <span className="reveal-text-container flex justify-center">
                   <span ref={addToRefs} className="reveal-text-item">Consultora Inmobiliaria</span>
                </span>
              </h1>
            </div>
        </div>

        {/* BOTTOM LEFT: Description (Alineado a la izquierda al fondo) */}
        <div className="mt-auto pb-16 md:pb-24 z-20 flex justify-start">
            <p ref={textRef} className="text-white/80 text-lg md:text-xl font-light max-w-2xl leading-relaxed text-left">
              Somos la consultora inmobiliaria liderada por arquitectos; el paso previo indispensable para garantizar el máximo valor en tus decisiones.
            </p>
        </div>

      </div>
    </section>
  );
};

